import{_ as t,o,c as r,ag as a}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Open in IDE","description":"","frontmatter":{"title":"Open in IDE","lang":"en-US"},"headers":[],"relativePath":"ide-integration.md","filePath":"ide-integration.md","lastUpdated":1784384975000}'),s={name:"ide-integration.md"};function n(i,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="open-in-ide" tabindex="-1">Open in IDE <a class="header-anchor" href="#open-in-ide" aria-label="Permalink to &quot;Open in IDE&quot;">​</a></h1><p>Every source path the dashboard shows — the failing call stack (&quot;Failed here&quot;), a run&#39;s test-case list, a test case&#39;s file, flaky lists, cluster evidence, the AI suggested-fix — is clickable. Hover a path and a small <strong>open in IDE</strong> control appears: click it to jump straight to that file (and line) in your local editor, or open the chooser to pick a specific method.</p><p>Because the dashboard runs in your browser while the source lives on your machine, the mapping from a repo-relative path (<code>tests/checkout.spec.ts</code>) to a real file is configured <strong>per browser</strong> and stored locally — it is never sent to the server.</p><h2 id="set-it-up" tabindex="-1">Set it up <a class="header-anchor" href="#set-it-up" aria-label="Permalink to &quot;Set it up&quot;">​</a></h2><ol><li>Hover any source path and click the <strong>⌄</strong> caret, then <strong>Configure…</strong> — or open it from the user menu (bottom-left) → <strong>Open in IDE…</strong>.</li><li>Set your <strong>workspace root</strong>: the absolute path of your local checkout, e.g. <code>/home/me/my-repo</code> (or <code>C:\\Users\\me\\my-repo</code> on Windows). Repo-relative paths are joined onto it, which is what VS Code needs to resolve a file.</li><li>Pick a <strong>method</strong> (or leave it on <strong>Auto</strong>) and close the dialog. Clicking a path now opens it in your editor.</li></ol><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>How it opens</th><th>Needs</th></tr></thead><tbody><tr><td><strong>VS Code</strong></td><td><code>vscode://file/&lt;abs-path&gt;:&lt;line&gt;</code> URL scheme</td><td>A workspace root (for the absolute path). Flavors: VS Code, Insiders, VSCodium, Cursor.</td></tr><tr><td><strong>JetBrains (URL)</strong></td><td><code>jetbrains://&lt;product&gt;/navigate/reference?project=&lt;name&gt;&amp;path=&lt;rel&gt;:&lt;line&gt;</code></td><td><a href="https://www.jetbrains.com/toolbox-app/" target="_blank" rel="noreferrer">JetBrains Toolbox</a>; the IDE product tag (e.g. <code>idea</code>, <code>webstorm</code>) and the open project name.</td></tr><tr><td><strong>JetBrains (local server)</strong></td><td><code>http://localhost:63342/api/file/&lt;path&gt;:&lt;line&gt;</code></td><td>The IDE running with the <strong><a href="https://plugins.jetbrains.com/plugin/19991-ide-remote-control" target="_blank" rel="noreferrer">IDE Remote Control</a></strong> plugin and <strong>Settings → Build → Debugger → &quot;Allow unsigned requests&quot;</strong> enabled.</td></tr><tr><td><strong>Auto</strong></td><td>Tries the JetBrains local server first, then falls back to a URL launch</td><td>Whatever the chosen fallback needs.</td></tr></tbody></table><h3 id="auto-—-try-all-stop-on-first-success" tabindex="-1">Auto — &quot;try all, stop on first success&quot; <a class="header-anchor" href="#auto-—-try-all-stop-on-first-success" aria-label="Permalink to &quot;Auto — &quot;try all, stop on first success&quot;&quot;">​</a></h3><p>Only the <strong>local server</strong> method can be confirmed from the browser: the dashboard sends it a <code>fetch</code> and, if the IDE answers, reports success. The <code>vscode://</code> and <code>jetbrains://</code> URL schemes are handed off to the operating system with <strong>no success signal</strong> — the browser&#39;s own &quot;Open &lt;app&gt;?&quot; prompt is the only real confirmation.</p><p>So <strong>Auto</strong> probes the JetBrains local server first (the detectable rung) and, if nothing answers, launches a single URL scheme (VS Code when a workspace root is set, otherwise <code>jetbrains://</code>) — reported honestly as &quot;opening… (can&#39;t confirm)&quot;. If you only ever use one editor, set the method explicitly to skip the probe.</p><div class="warning custom-block"><p class="custom-block-title">HTTPS and the local server</p><p>Browsers block a page served over <strong>HTTPS</strong> from calling <code>http://localhost</code> (mixed content) — Firefox and Safari always, Chrome increasingly. The local-server method (and Auto&#39;s detectable rung) therefore works best when the dashboard is served over <strong>http / localhost</strong>. Over HTTPS, Auto still falls back to the URL schemes, which are unaffected.</p></div><h2 id="per-project-overrides" tabindex="-1">Per-project overrides <a class="header-anchor" href="#per-project-overrides" aria-label="Permalink to &quot;Per-project overrides&quot;">​</a></h2><p>If you view several projects that live in different local checkouts (or a monorepo), open <strong>Configure…</strong> from a path inside that project — the dialog then offers a <strong>workspace root override</strong> and a <strong>JetBrains project name</strong> just for that project. Everything else falls back to your global settings.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>All of this — the method, workspace root(s), editor flavor and JetBrains product/port — lives in your browser&#39;s <code>localStorage</code> under <code>piwi-ide-prefs</code>. Nothing about your local filesystem is sent to the Piwi server.</p>',15)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
